sql:
SELECT establishments.name, establishments.postcode
FROM establishments
WHERE establishments.fsa_id IN (SELECT reporting.fsa_id FROM reporting);

SELECT AVG(favorite_count) as average_favorite_count
FROM (
  SELECT COUNT(favorite_id) as favorite_count
  FROM favorites
  GROUP BY user_id
);

external_knowledge:
- "highly reviewed spots" refers to establishments with more than 5 reviews; 
- "average feedback" is the average rating of the establishment;
- "most recent inspection dates" are the latest dates when an inspection took place for these establishments;
- "when their licenses are set to expire" means the latest expiry date for the licenses of the establishments.

- 'top-rated' refers to establishments with ratings of 4.5 or higher;
- 'recently inspected' indicates inspections within the last month;
- 'eateries' specifically refers to food establishments that offer Indian cuisine;
- 'Islington' implies 'The Borough of Islington'.
